// src/components/About/About.js
import React from 'react';
import './About.css';
import rafaelImage from '../../images/rafael.jpg'; // Asegúrate de tener la imagen en la ruta correcta

const About = () => {
  return (
    <section id="about" className="section about-section">
      <div className="container">
        <h2>About Me</h2>
        <div className="about-content">
          <div className="about-text">
            <p>I am Rafael Hernández, a Mechatronics Engineer with expertise in:</p>
            <ul>
              <li>Robotics</li>
              <li>Artificial Intelligence (AI)</li>
              <li>Software Development</li>
            </ul>
            <p>Currently, at Mirai Innovation Research Institute, I lead:</p>
            <ul>
              <li>Educational programs</li>
              <li>High-impact technological projects</li>
            </ul>
            <p>My goals include contributing to leading technology companies and, in the long term, founding a startup focused on robotics to address social challenges and bridge the technological gap in Mexico.</p>
          </div>
          <div className="about-image">
            <img src={rafaelImage} alt="Rafael Hernández, Mechatronics Engineer" />
          </div>
        </div>
      </div>
    </section>
  );
};

export default About;
